import React, { Fragment, useState } from 'react';
import axios from 'axios'; // Import axios for making HTTP requests

const Login = ({ setAuth }) => {
  // State to hold form data
  const [formData, setFormData] = useState({
    e_mail: '',
    user_password: ''
  });

  // onChange function to update state
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  // Function to handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Make a POST request to the login endpoint
      const response = await axios.post('http://localhost:5000/login', formData);

      // Check if the response contains a JWT token
      if (response.data.jwtToken) {
        // Set authentication to true and store JWT token in local storage
        localStorage.setItem('token', response.data.jwtToken);
        setAuth(true);
      } else {
        // Handle error if no token is received
        console.error('No JWT token received');
      }
    } catch (error) {
      // Handle any errors that occur during the request
      console.error('Error:', error);
    }
  };

  return (
    <Fragment>
      <h1>Login</h1>
      <form onSubmit={handleSubmit}>
        <input
          type="email"
          name="e_mail"
          placeholder="Email"
          onChange={handleChange}
          value={formData.e_mail}
          required
        />
        <input
          type="password"
          name="user_password"
          placeholder="Password"
          onChange={handleChange}
          value={formData.user_password}
          required
        />
        <button type="submit">Login</button>
      </form>
    </Fragment>
  );
};

export default Login;
